  it('calls onReset with correct chatJid and groupFolder for registered chat', async () => {
    const onReset = vi.fn().mockResolvedValue(undefined);
    const opts = createTestOpts({ onReset });
    await setupChannel(opts);

    const handler = currentBot().commandHandlers.get('reset')!;
    const ctx = createTextCtx({ text: '/reset', chatId: 100200300 });
