      registeredGroups: vi.fn(() => ({})),
    });
    await setupChannel(opts);

    const handler = currentBot().commandHandlers.get('reset')!;
    const ctx = createTextCtx({ text: '/reset', chatId: 999999 });
    await handler(ctx);

