### Full `credential-proxy.ts` After All Changes

For reference, the complete file after changes 1a–1e:

```typescript
/**
 * Credential proxy for container isolation.
 * Containers connect here instead of directly to the Anthropic API.
 * The proxy injects real credentials so containers never see them.
 *
 * Two auth modes:
 *   API key:  Proxy injects x-api-key on every request.
 *   OAuth:    Container CLI exchanges its placeholder token for a temp
 *             API key via /api/oauth/claude_cli/create_api_key.
 *             Proxy reads the current OAuth token from
 *             ~/.claude/.credentials.json on each exchange request,
 *             so token refreshes are picked up automatically.
 */
import fs from 'fs';
import { createServer, Server } from 'http';
import { request as httpsRequest } from 'https';
import { request as httpRequest, RequestOptions } from 'http';
import os from 'os';
import path from 'path';

import { readEnvFile } from './env.js';
import { logger } from './logger.js';

export type AuthMode = 'api-key' | 'oauth';

export interface ProxyConfig {
  authMode: AuthMode;
}

/**
 * Read the current OAuth access token from Claude Code's credentials file.
 * Called at request time so the proxy always uses the freshest token,
 * even after automatic token refresh by `claude login`.
 */
export function readOAuthToken(
  credentialsPath?: string,
): string | null {
  const filePath =
    credentialsPath ||
    path.join(os.homedir(), '.claude', '.credentials.json');

  try {
    const raw = fs.readFileSync(filePath, 'utf-8');
    const data = JSON.parse(raw);
    const token = data?.claudeAiOauth?.accessToken;
    if (!token || typeof token !== 'string') {
      logger.warn(
        { credentialsPath: filePath },
        'OAuth credentials file missing claudeAiOauth.accessToken',
      );
      return null;
    }
    return token;
  } catch (err: any) {
    if (err.code === 'ENOENT') {
      logger.warn(
        { credentialsPath: filePath },
        'OAuth credentials file not found. Run `claude login` to authenticate.',
      );
    } else if (err instanceof SyntaxError) {
      logger.warn(
        { credentialsPath: filePath, err: err.message },
        'OAuth credentials file contains invalid JSON',
      );
    } else {
      logger.warn(
        { credentialsPath: filePath, err: err.message },
        'Failed to read OAuth credentials file',
      );
    }
    return null;
  }
}

export function startCredentialProxy(
  port: number,
  host = '127.0.0.1',
): Promise<Server> {
  const secrets = readEnvFile([
    'ANTHROPIC_API_KEY',
    'ANTHROPIC_BASE_URL',
  ]);

  const authMode: AuthMode = secrets.ANTHROPIC_API_KEY ? 'api-key' : 'oauth';

  const upstreamUrl = new URL(
    secrets.ANTHROPIC_BASE_URL || 'https://api.anthropic.com',
  );
  const isHttps = upstreamUrl.protocol === 'https:';
  const makeRequest = isHttps ? httpsRequest : httpRequest;

  return new Promise((resolve, reject) => {
    const server = createServer((req, res) => {
      const chunks: Buffer[] = [];
      req.on('data', (c) => chunks.push(c));
      req.on('end', () => {
        const body = Buffer.concat(chunks);
        const headers: Record<string, string | number | string[] | undefined> =
          {
            ...(req.headers as Record<string, string>),
            host: upstreamUrl.host,
            'content-length': body.length,
          };

        // Strip hop-by-hop headers that must not be forwarded by proxies
        delete headers['connection'];
        delete headers['keep-alive'];
        delete headers['transfer-encoding'];

        if (authMode === 'api-key') {
          // API key mode: inject x-api-key on every request
          delete headers['x-api-key'];
          headers['x-api-key'] = secrets.ANTHROPIC_API_KEY;
        } else {
          // OAuth mode: read the current token from ~/.claude/.credentials.json
          // on every request so token refreshes are picked up automatically.
          // Only inject when the container sends an Authorization header
          // (exchange request + auth probes). Post-exchange requests use
          // x-api-key only, so they pass through without token injection.
          if (headers['authorization']) {
            delete headers['authorization'];
            const token = readOAuthToken();
            if (token) {
              headers['authorization'] = `Bearer ${token}`;
            } else {
              logger.error(
                'OAuth token unavailable — request will likely fail with 401',
              );
            }
          }
        }

        const upstream = makeRequest(
          {
            hostname: upstreamUrl.hostname,
            port: upstreamUrl.port || (isHttps ? 443 : 80),
            path: req.url,
            method: req.method,
            headers,
          } as RequestOptions,
          (upRes) => {
            res.writeHead(upRes.statusCode!, upRes.headers);
            upRes.pipe(res);
          },
        );

        upstream.on('error', (err) => {
          logger.error(
            { err, url: req.url },
            'Credential proxy upstream error',
          );
          if (!res.headersSent) {
            res.writeHead(502);
            res.end('Bad Gateway');
          }
        });

        upstream.write(body);
        upstream.end();
      });
    });

    server.listen(port, host, () => {
      const credentialsFile = path.join(os.homedir(), '.claude', '.credentials.json');
      const hasCredentials = authMode === 'oauth' ? fs.existsSync(credentialsFile) : true;
      logger.info(
        { port, host, authMode, credentialsFile: authMode === 'oauth' ? credentialsFile : undefined, hasCredentials },
        'Credential proxy started',
      );
      if (authMode === 'oauth' && !hasCredentials) {
        logger.warn(
          { credentialsFile },
          'OAuth mode but credentials file not found. Run `claude login` to authenticate.',
        );
      }
      resolve(server);
    });

    server.on('error', reject);
  });
}

/** Detect which auth mode the host is configured for. */
export function detectAuthMode(): AuthMode {
  const secrets = readEnvFile(['ANTHROPIC_API_KEY']);
  return secrets.ANTHROPIC_API_KEY ? 'api-key' : 'oauth';
}
```

