/**
 * Read the full credentials object from disk.
 * Used by refresh logic to get refreshToken, expiresAt, scopes, etc.
 */
export function readCredentials(
  credentialsPath?: string,
): Record<string, any> | null {
  const filePath =
    credentialsPath ||
    path.join(os.homedir(), '.claude', '.credentials.json');

  try {
    const raw = fs.readFileSync(filePath, 'utf-8');
    return JSON.parse(raw);
  } catch {
    return null;
  }
}

/**
 * Atomically write credentials to disk.
 * Uses write-to-temp + rename to prevent corruption.
 */
export function writeCredentials(
  data: Record<string, any>,
  credentialsPath?: string,
): void {
  const filePath =
    credentialsPath ||
    path.join(os.homedir(), '.claude', '.credentials.json');
  const tmpPath = filePath + '.tmp.' + process.pid;
  fs.writeFileSync(tmpPath, JSON.stringify(data, null, 2) + '\n', {
    mode: 0o600,
  });
  fs.renameSync(tmpPath, filePath);
}

/**
 * Refresh the OAuth access token using the refresh token.
 * POSTs to Anthropic's token endpoint, writes new credentials to disk.
 * Returns true on success, false on failure.
 */
export async function refreshOAuthToken(
  credentialsPath?: string,
): Promise<boolean> {
  if (refreshInProgress) {
    logger.debug('Token refresh already in progress, skipping');
    return false;
  }
  refreshInProgress = true;

  try {
    const creds = readCredentials(credentialsPath);
    if (!creds?.claudeAiOauth?.refreshToken) {
      logger.error('No refresh token available — cannot refresh');
      return false;
    }

    const oauth = creds.claudeAiOauth;
    const scopes = Array.isArray(oauth.scopes)
      ? oauth.scopes
      : DEFAULT_SCOPES;

    const postBody = JSON.stringify({
      grant_type: 'refresh_token',
      refresh_token: oauth.refreshToken,
      client_id: CLIENT_ID,
      scope: scopes.join(' '),
    });

    const url = new URL(TOKEN_URL);

    const response = await new Promise<{
      statusCode: number;
      body: string;
    }>((resolve, reject) => {
      // Use https.request (default import) so tests can mock via vi.spyOn
      const req = https.request(
        {
          hostname: url.hostname,
          port: 443,
          path: url.pathname,
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            'Content-Length': Buffer.byteLength(postBody),
          },
          timeout: 15000,
        },
        (res) => {
          const chunks: Buffer[] = [];
          res.on('data', (c: Buffer) => chunks.push(c));
          res.on('end', () => {
            resolve({
              statusCode: res.statusCode!,
              body: Buffer.concat(chunks).toString(),
            });
          });
        },
      );
      req.on('error', reject);
      req.on('timeout', () => {
        req.destroy(new Error('Token refresh request timed out'));
      });
      req.write(postBody);
      req.end();
    });

    if (response.statusCode !== 200) {
      const isAuthError =
        response.statusCode === 401 || response.statusCode === 403;
      logger.error(
        { statusCode: response.statusCode, body: response.body.slice(0, 200) },
        isAuthError
          ? 'OAuth refresh token is invalid. Run `claude login` to re-authenticate.'
          : 'OAuth token refresh failed',
      );
      if (isAuthError && alertFn) {
        alertFn(
          'OAuth refresh token is invalid. Run `claude login` to re-authenticate.',
        );
      }
      return false;
    }

    const data = JSON.parse(response.body);
    const newAccessToken = data.access_token;
    const newRefreshToken = data.refresh_token || oauth.refreshToken;
    const expiresIn = data.expires_in || 28800;
    const newExpiresAt = Date.now() + expiresIn * 1000;

    // Build updated credentials, preserving all existing fields
    const updatedCreds = {
      ...creds,
      claudeAiOauth: {
        ...oauth,
        accessToken: newAccessToken,
        refreshToken: newRefreshToken,
        expiresAt: newExpiresAt,
      },
    };

    const filePath =
      credentialsPath ||
      path.join(os.homedir(), '.claude', '.credentials.json');
    writeCredentials(updatedCreds, filePath);

    const expiresDate = new Date(newExpiresAt);
    logger.info(
      {
        expiresAt: expiresDate.toISOString(),
        expiresInHours: (expiresIn / 3600).toFixed(1),
      },
      'OAuth token refreshed successfully',
    );

    consecutiveFailures = 0;
    return true;
  } catch (err: any) {
    logger.error({ err: err.message }, 'OAuth token refresh failed');
    return false;
  } finally {
    refreshInProgress = false;
  }
}

/**
 * Schedule proactive token refresh based on expiresAt in credentials.
 * Refreshes at 75% of remaining lifetime to prevent expiry.
 * Call once at startup (OAuth mode only).
 */
export function scheduleTokenRefresh(
  credentialsPath?: string,
  onAlert?: (message: string) => void,
): void {
  // Clear any existing timer (safe to call multiple times)
  stopTokenRefresh();
  alertFn = onAlert;

  const creds = readCredentials(credentialsPath);
  const expiresAt = creds?.claudeAiOauth?.expiresAt;

  const now = Date.now();
  let delayMs: number;

  if (!expiresAt || typeof expiresAt !== 'number' || expiresAt <= now) {
    logger.warn(
      { expiresAt: expiresAt || 'missing' },
      'OAuth token expired or expiresAt missing, refreshing immediately',
    );
    delayMs = 0;
  } else if (expiresAt - now < 5 * 60 * 1000) {
    logger.warn(
      { expiresInMinutes: ((expiresAt - now) / 60000).toFixed(1) },
      'OAuth token expiring soon, refreshing immediately',
    );
    delayMs = 0;
  } else {
    const remaining = expiresAt - now;
    delayMs = Math.floor(remaining * 0.75);
    const refreshAt = new Date(now + delayMs);
    const expiresDate = new Date(expiresAt);
    logger.info(
      {
        expiresAt: expiresDate.toISOString(),
        refreshAt: refreshAt.toISOString(),
        delayHours: (delayMs / 3600000).toFixed(1),
      },
      'OAuth token refresh scheduled',
    );
  }

  // Token health logging
  const healthExp = creds?.claudeAiOauth?.expiresAt;
  if (healthExp && typeof healthExp === 'number') {
    const remaining = healthExp - Date.now();
    const hours = Math.floor(remaining / 3600000);
    const minutes = Math.floor((remaining % 3600000) / 60000);
    logger.info(
      {
        expiresIn: `${hours}h ${minutes}m`,
        expiresAt: new Date(healthExp).toISOString(),
      },
      'OAuth token health check',
    );
  }

  const doRefresh = async () => {
    const success = await refreshOAuthToken(credentialsPath);
    if (success) {
      consecutiveFailures = 0;
      scheduleTokenRefresh(credentialsPath, onAlert);
    } else {
      consecutiveFailures++;
      if (consecutiveFailures === 3 && alertFn) {
        const creds2 = readCredentials(credentialsPath);
        const exp = creds2?.claudeAiOauth?.expiresAt;
        const expStr = exp ? new Date(exp).toISOString() : 'unknown';
        alertFn(
          `OAuth refresh has failed 3 times. Token expires at ${expStr}. Run \`claude login\` if needed.`,
        );
      }
      // Retry backoff: 5 min for failures 1-3, 1 hour for 4+
      const retryMs =
        consecutiveFailures <= 3 ? 5 * 60 * 1000 : 60 * 60 * 1000;
      logger.warn(
        { consecutiveFailures, retryInMinutes: retryMs / 60000 },
        'OAuth refresh failed, scheduling retry',
      );
      refreshTimer = setTimeout(doRefresh, retryMs);
    }
  };

  if (delayMs === 0) {
    refreshTimer = setTimeout(doRefresh, 0);
  } else {
    refreshTimer = setTimeout(doRefresh, delayMs);
  }
}

/**
 * Stop the token refresh timer. Called during shutdown.
 */
export function stopTokenRefresh(): void {
  if (refreshTimer) {
    clearTimeout(refreshTimer);
    refreshTimer = null;
  }
}

