    it('handles refresh token rotation (AC-1.4)', async () => {
      const { tmpDir, credFile } = makeTmpCreds();
      mockHttpsSuccess({
        access_token: 'new-token',
        refresh_token: 'rotated-refresh',
        expires_in: 28800,
      });

      await refreshOAuthToken(credFile);

      const updated = JSON.parse(fs.readFileSync(credFile, 'utf-8'));
      expect(updated.claudeAiOauth.refreshToken).toBe('rotated-refresh');

      fs.rmSync(tmpDir, { recursive: true, force: true });
    });

    it('preserves existing fields (AC-1.5)', async () => {
      const { tmpDir, credFile } = makeTmpCreds();
      mockHttpsSuccess({
        access_token: 'new',
        expires_in: 28800,
      });

      await refreshOAuthToken(credFile);

      const updated = JSON.parse(fs.readFileSync(credFile, 'utf-8'));
      expect(updated.claudeAiOauth.subscriptionType).toBe('max');
      expect(updated.claudeAiOauth.rateLimitTier).toBe('default');

      fs.rmSync(tmpDir, { recursive: true, force: true });
    });

    it('returns false on network error (AC-1.6)', async () => {
      const { tmpDir, credFile } = makeTmpCreds();
      vi.spyOn(https, 'request').mockImplementation((_opts: any, _cb: any) => {
        const mockReq = {
          on: vi.fn((event: string, handler: any) => {
            if (event === 'error') {
              setImmediate(() => handler(new Error('ECONNREFUSED')));
            }
          }),
          write: vi.fn(),
          end: vi.fn(),
          destroy: vi.fn(),
        };
        return mockReq as any;
      });

      const result = await refreshOAuthToken(credFile);
      expect(result).toBe(false);

      fs.rmSync(tmpDir, { recursive: true, force: true });
    });

    it('returns false on 401 invalid refresh token (AC-1.7)', async () => {
      const { tmpDir, credFile } = makeTmpCreds();
      mockHttpsError(401, '{"error":"invalid_grant"}');

      const result = await refreshOAuthToken(credFile);
      expect(result).toBe(false);
      expect(mockLogger.error).toHaveBeenCalledWith(
        expect.objectContaining({ statusCode: 401 }),
        expect.stringContaining('invalid'),
      );

      fs.rmSync(tmpDir, { recursive: true, force: true });
    });

    it('sets file permissions to 0600 (AC-1.9)', async () => {
      const { tmpDir, credFile } = makeTmpCreds();
      mockHttpsSuccess({ access_token: 'new', expires_in: 28800 });

      await refreshOAuthToken(credFile);

      const stat = fs.statSync(credFile);
      expect(stat.mode & 0o777).toBe(0o600);

      fs.rmSync(tmpDir, { recursive: true, force: true });
    });

    it('prevents concurrent refresh attempts with mutex (AC-3.4)', async () => {
      const { tmpDir, credFile } = makeTmpCreds();
      let requestCount = 0;
      vi.spyOn(https, 'request').mockImplementation((_opts: any, cb: any) => {
        requestCount++;
