        expect.anything(),
        expect.stringContaining('refreshing immediately'),
      );

      fs.rmSync(tmpDir, { recursive: true, force: true });
    });

    it('refreshes immediately if expiresAt is missing (AC-2.4)', () => {
      const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'nanoclaw-sched-'));
      const credFile = path.join(tmpDir, '.credentials.json');
      fs.writeFileSync(
        credFile,
