          claudeAiOauth: {
            accessToken: 'valid',
            refreshToken: 'refresh',
            expiresAt: Date.now() + 8 * 60 * 60 * 1000,
          },
        }),
      );

      scheduleTokenRefresh(credFile);
      stopTokenRefresh();

      // Advance past when the timer would have fired — nothing should happen
      vi.advanceTimersByTime(8 * 60 * 60 * 1000);

