        )
        self.reflect_timeout = int(
            os.environ.get("EXTRACT_REFLECT_TIMEOUT_SEC", "600")
        )
        self.max_text_words = int(
            os.environ.get("EXTRACT_MAX_TEXT_WORDS", "500000")
        )
        self.log_level = os.environ.get("EXTRACT_LOG_LEVEL", "info")


def get_config() -> Config:
    """Get the service configuration."""
    return Config()

