journalctl --user -u transcription.service --since "2 days ago" --no-pager 2>&1 | grep -E "Downloading|Audio:|Done in|POST /transcribe" | awk '
BEGIN { busy = 0; busy_url = ""; busy_since = "" }
/Downloading/ { 
    ts = $1 " " $2 " " $3
    url = $NF
    gsub(/\.\.\./, "", url)
    cur_ts = ts; cur_url = url; cur_got_audio = 0
}
/Audio:/ { cur_got_audio = 1 }
/Done in/ { busy = 0; busy_url = ""; busy_since = "" }
/POST \/transcribe/ {
    if (cur_url != "" && !cur_got_audio) {
        # This was a failure
        if (busy) {
            print "FAIL+BUSY | " cur_ts " | " cur_url " | GPU busy with: " busy_url " since " busy_since
        } else {
            print "FAIL+IDLE | " cur_ts " | " cur_url
        }
    }
    if (cur_got_audio) {
        # This succeeded, GPU is now busy transcribing
        busy = 1; busy_url = cur_url; busy_since = cur_ts
    }
    cur_url = ""; cur_got_audio = 0
}
'
